previewCss:
.darma-loader-darma-custom-594 {color: var(--loader-color, #0284c7);
  --loader-secondary-color: #7dd3fc;
  --loader-bg: #ffffff;
   width: 100px;
   height: 30px;
   display: flex;
}
.darma-loader-darma-custom-594:before  {
  content: "";
   background: currentColor;
   width: 15px;
   clip-path: polygon(0 10px,calc(100% - 15px) 10px,calc(100% - 15px) 0,100% 50%,calc(100% - 15px) 100%,calc(100% - 15px) calc(100% - 10px),0 calc(100% - 10px));
   animation: darma-loader-darma-custom-594-l1 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-594-l1  {
  90%,100%{flex-grow: 1}
}

